import{_ as a,c as e,G as t,b as r}from"./chunks/framework.BrC0DRXd.js";const s=JSON.parse('{"title":"本人简介","description":"这是本人的简介","frontmatter":{"title":"本人简介","tags":["必读"],"categories":["必读"],"date":"2026-03-19T00:00:00.000Z","description":"这是本人的简介","head":[["link",{"rel":"canonical","href":"https://knotens.org/posts/自我介绍"}]]},"headers":[],"relativePath":"posts/自我介绍.md","filePath":"posts/自我介绍.md","lastUpdated":1773922428000}');const o=a({name:"posts/自我介绍.md"},[["render",function(a,s,o,p,i,n){return r(),e("div",null,s[0]||(s[0]=[t('<h3 id="_1、自我介绍" tabindex="-1">1、自我介绍？ <a class="header-anchor" href="#_1、自我介绍" aria-label="Permalink to &quot;1、自我介绍？&quot;">​</a></h3><p>我是一个同时对计算机和人文社科非常感兴趣的文科生，平时酷爱折腾各类效率工具、逛技术站点。</p><p>我认为我有必要加入（或者为未来的我准备）一个高质量圈子，通过身边的圈子倒逼我的进步。</p><p>自我大学以后，我的社交更多趋向于这种主动选择，而远离了以前中学的封闭式管理环境带来的强制社交。</p><h3 id="_2、对社区的看法" tabindex="-1">2、对社区的看法？ <a class="header-anchor" href="#_2、对社区的看法" aria-label="Permalink to &quot;2、对社区的看法？&quot;">​</a></h3><p>因为本人有轻度的fomo，为了网罗天下资讯于一屋，我开始用rss阅读器筛选、聚合有价值的信息源。</p><p>我深耕web3行业，并对web3这个理念被币圈部分“坏人”用来割韭菜感到痛心疾首。</p><h3 id="_3、希望在此" tabindex="-1">3、希望在此？ <a class="header-anchor" href="#_3、希望在此" aria-label="Permalink to &quot;3、希望在此？&quot;">​</a></h3><p>我正处于一个“大量输入”到“适量输入，适量输出”的转型期。我现在正处于多种输出形式的混合：当知乎博主写文章和回答、自建私域进行广播、加入高质量社群进行分享等。</p><p>同时在加速主义和工业党盛行的当代，盲目的工具崇拜成为趋势。技术上升，人文下降。我希望我能够为各技术社群带来一些人文气，为人和工具厘清界限。</p><p>技术讨论里偶尔有人追问一句“这对人意味着什么”，不是坏事。</p><p>人是拿来爱的 ，工具是拿来用的。这世界一团糟，是因为工具被拿来爱了，而人却被拿来用了。——索菲·金塞拉《购物狂的异想世界》</p>',12)]))}]]);export{s as __pageData,o as default};
